from dataclasses import dataclass
from typing import Any, Optional, List, Tuple

@dataclass
class Event:
    start: float
    end: float
    title: str
    priority: int  # higher = more important

class Calendar:
    def __init__(self):
        self._events: List[Event] = []

    def add_event(self, event: Event) -> List[Event]:
        if event.start >= event.end:
            raise ValueError("Start must be less than end")

        conflicts = [e for e in self._events if e.start < event.end and e.end > event.start]

        if not conflicts:
            self._events.append(event)
            self._events.sort(key=lambda e: e.start)
            return []

        if event.priority > max(e.priority for e in conflicts):
            modified_removed = []
            new_events = []
            for e in self._events:
                if e in conflicts:
                    modified_removed.append(e)
                    if e.start < event.start:
                        new_events.append(Event(e.start, event.start, e.title, e.priority))
                    if e.end > event.end:
                        new_events.append(Event(event.end, e.end, e.title, e.priority))
                else:
                    new_events.append(e)
            new_events.append(event)
            self._events = new_events
            self._events.sort(key=lambda e: e.start)
            return modified_removed
        else:
            sorted_existing = sorted(self._events, key=lambda e: e.start)
            fragments = []
            current_start = event.start
            current_end = event.end

            for e in sorted_existing:
                if e.end <= current_start:
                    continue
                if e.start >= current_end:
                    break
                if e.start > current_start:
                    fragments.append(Event(current_start, e.start, event.title, event.priority))
                current_start = max(current_start, e.end)

            if current_start < current_end:
                fragments.append(Event(current_start, current_end, event.title, event.priority))

            self._events.extend(fragments)
            self._events.sort(key=lambda e: e.start)
            return fragments

    def get_events(self, start: float, end: float) -> List[Event]:
        return sorted(
            [e for e in self._events if e.start < end and e.end > start],
            key=lambda e: e.start
        )

    def free_slots(self, start: float, end: float, min_duration: float = 0) -> List[Tuple[float, float]]:
        events = sorted(
            [e for e in self._events if e.start < end and e.end > start],
            key=lambda e: e.start
        )
        slots = []
        current = start
        for e in events:
            if e.start > current:
                slot_start = current
                slot_end = min(e.start, end)
                if slot_end - slot_start >= min_duration:
                    slots.append((slot_start, slot_end))
            current = max(current, e.end)
            if current >= end:
                break
        if current < end:
            if end - current >= min_duration:
                slots.append((current, end))
        return slots

    def utilization(self, start: float, end: float) -> float:
        total = end - start
        if total <= 0:
            return 0.0
        occupied = 0.0
        events = sorted(
            [e for e in self._events if e.start < end and e.end > start],
            key=lambda e: e.start
        )
        current = start
        for e in events:
            if e.start > current:
                current = e.start
            if e.end > current:
                occupied += min(e.end, end) - current
                current = e.end
            if current >= end:
                break
        return occupied / total
